  { key: 'name', title: '姓名', dataIndex: 'name', width: 180 },
  { key: 'role', title: '岗位', dataIndex: 'role', width: 160 },
  { key: 'score', title: '分数', dataIndex: 'score', width: 120, sortable: true }
